#!/usr/bin/env node
// Generates web/src/curvegpu/shader_bundle.generated.ts by inlining all WGSL
// shader files referenced by the library. Run via `npm run build:shaders`.
//
// The generated file installs the bundle via setBundledShaders() so that the
// library can operate without a web server for shader files.

import { readFileSync, writeFileSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const webDir = resolve(__dirname, "..");
const repoRoot = resolve(webDir, "..");
const outPath = resolve(webDir, "src/curvegpu/shader_bundle.generated.ts");

// All unique WGSL file paths served under /shaders/ by the dev server.
// Update this list when new shaders are added to curves.ts.
const SHADER_PATHS = [
  "/shaders/curves/bn254/fp_arith.wgsl",
  "/shaders/curves/bn254/fr_arith.wgsl",
  "/shaders/curves/bn254/fr_vector.wgsl",
  "/shaders/curves/bn254/fr_ntt.wgsl",
  "/shaders/curves/bn254/fr_plonk_quotient.wgsl",
  "/shaders/curves/bn254/g1_io.wgsl",
  "/shaders/curves/bn254/g2_arith.wgsl",
  "/shaders/curves/bn254/g2_io.wgsl",
  "/shaders/curves/bls12_381/fp_arith.wgsl",
  "/shaders/curves/bls12_381/fr_arith.wgsl",
  "/shaders/curves/bls12_381/fr_vector.wgsl",
  "/shaders/curves/bls12_381/fr_ntt.wgsl",
  "/shaders/curves/bls12_381/fr_plonk_quotient.wgsl",
  "/shaders/curves/bls12_381/g1_io.wgsl",
  "/shaders/curves/bls12_381/g2_arith.wgsl",
  "/shaders/curves/bls12_381/g2_io.wgsl",
  "/shaders/curves/bls12_377/fp_arith.wgsl",
  "/shaders/curves/bls12_377/fr_arith.wgsl",
  "/shaders/curves/bls12_377/fr_vector.wgsl",
  "/shaders/curves/bls12_377/fr_ntt.wgsl",
  "/shaders/curves/bls12_377/fr_plonk_quotient.wgsl",
  "/shaders/curves/bls12_377/g1_io.wgsl",
  "/shaders/curves/bls12_377/g2_arith.wgsl",
  "/shaders/curves/bls12_377/g2_io.wgsl",
  "/shaders/common/g1_core.wgsl",
  "/shaders/common/g1_ops_bindings.wgsl",
  "/shaders/common/g1_ops_main.wgsl",
  "/shaders/common/g1_msm_bindings.wgsl",
  "/shaders/common/g2_ops_bindings.wgsl",
  "/shaders/common/g2_ops_main.wgsl",
  "/shaders/common/g2_msm_bindings.wgsl",
  "/shaders/common/g1_msm_jac.wgsl",
  "/shaders/common/g2_msm_jac.wgsl",
];

function escapeForTemplateLiteral(text) {
  return text.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/\$\{/g, "\\${");
}

const entries = [];
for (const urlPath of SHADER_PATHS) {
  const filePath = resolve(repoRoot, urlPath.slice(1)); // strip leading /
  const content = readFileSync(filePath, "utf8");
  const escaped = escapeForTemplateLiteral(content);
  entries.push(`  ${JSON.stringify(urlPath)}: \`${escaped}\``);
}

const output = `\
// Auto-generated by web/scripts/bundle-shaders.mjs — do not edit manually.
// Run \`npm run build:shaders\` to regenerate.
import { setBundledShaders } from "./shaders.js";

setBundledShaders({
${entries.join(",\n")},
});
`;

writeFileSync(outPath, output, "utf8");
console.log(`Wrote ${SHADER_PATHS.length} shaders to ${outPath}`);
